"use client";

import Image from "next/image";
import Link from "next/link";
import { BarChart3, BadgeCheck, Boxes, Check, CircleDollarSign, LayoutDashboard, LoaderCircle, LogOut, Package, Plus, RefreshCw, Search, Settings, ShoppingBag, Star, Tag, Trash2, Users, X } from "lucide-react";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { getSupabase, getSupabasePublicConfigError } from "@/lib/supabase";
import { money, products as fallbackProducts } from "@/lib/products";
import { trackEvent } from "@/lib/analytics";
import { defaultSiteContent, type SiteContent } from "@/lib/site-content";

type LiveOrder={id:string;order_number:string;customer_name:string;phone:string;total:number;status:string;payment_status:string;created_at:string;shipping_address?:{location?:string;address?:string}|null;order_items?:{product_name:string;quantity:number;unit_price:number}[]};
type LiveVariant={id?:string;name:string;value:string;stock:number;price_delta?:number|null};
type LiveProduct={id:string;name:string;slug:string;description?:string;benefits?:string[];price:number;stock:number;is_active:boolean;is_featured?:boolean;images:string[];category_id?:string|null;product_variants?:LiveVariant[]};
type Category={id:string;name:string;slug:string};
type LiveReview={id:string;customer_name:string;rating:number;title?:string|null;body:string;is_verified:boolean;moderation_status:"pending"|"approved"|"rejected";created_at:string;products:{name:string}|{name:string}[]|null};
type Coupon={id:string;code:string;discount_type:"percent"|"fixed";discount_value:number;min_order:number;max_uses:number|null;used_count:number;starts_at:string;expires_at:string|null;single_use:boolean;is_active:boolean};
type ShippingMethod={id:string;zone_id:string;name:string;code:string;method_type:"flat_rate"|"pickup";flat_rate:number;free_shipping_threshold:number|null;estimated_min_days:number;estimated_max_days:number;is_active:boolean;sort_order:number;shipping_zones:{name:string;code:string}|{name:string;code:string}[]|null};
type AdminData={orders:LiveOrder[];products:LiveProduct[];categories:Category[];reviews:LiveReview[];coupons:Coupon[];shippingMethods:ShippingMethod[];siteContent?:SiteContent;admin?:{full_name?:string}};
const statusLabels:Record<string,string>={pending:"Хүлээгдэж байна",confirmed:"Баталгаажсан",packing:"Бэлтгэж байна",shipped:"Хүргэлтэд",delivered:"Хүргэгдсэн",cancelled:"Цуцлагдсан",refunded:"Буцаагдсан"};
const timestampSlug=()=>{const now=new Date();const pad=(value:number)=>String(value).padStart(2,"0");return `product-${now.getFullYear()}${pad(now.getMonth()+1)}${pad(now.getDate())}-${pad(now.getHours())}${pad(now.getMinutes())}${pad(now.getSeconds())}`};
const safeSlug=(value:string)=>value.trim().toLowerCase().replace(/[^a-z0-9-]+/g,"-").replace(/-+/g,"-").replace(/^-|-$/g,"").slice(0,160);
const productSlug=(slug:string,name:string)=>safeSlug(slug)||safeSlug(name)||timestampSlug();
const normalizeWholeNumber=(value:string)=>Math.max(0,Math.round(Number(value.replace(/[^\d]/g,""))||0));
const imageUploadTypes=new Set(["image/jpeg","image/png","image/webp"]);

export default function AdminPage(){
  const supabase=getSupabase();
  const [tab,setTab]=useState("Хяналтын самбар");
  const [session,setSession]=useState<string|null>(null);
  const [authReady,setAuthReady]=useState(!supabase);
  const [data,setData]=useState<AdminData|null>(null);
  const [loading,setLoading]=useState(false);
  const [error,setError]=useState("");
  const load=useCallback(async(token?:string|null)=>{if(!token)return;setLoading(true);setError("");try{const response=await fetch("/api/admin",{headers:{authorization:`Bearer ${token}`}});const result=await response.json();if(!response.ok)throw new Error(result.error||"Өгөгдөл ачаалж чадсангүй.");setData(result)}catch(cause){setError(cause instanceof Error?cause.message:"Алдаа гарлаа.")}finally{setLoading(false)}},[]);
  useEffect(()=>{if(window.location.pathname.endsWith("/admin/products"))setTab("Бүтээгдэхүүн");else if(window.location.pathname.endsWith("/admin/orders"))setTab("Захиалга");else if(window.location.pathname.endsWith("/admin/content"))setTab("Контент")},[]);
  useEffect(()=>{if(!supabase)return;supabase.auth.getSession().then(({data:{session}})=>{const token=session?.access_token||null;setSession(token);setAuthReady(true);if(token)load(token)});const {data:{subscription}}=supabase.auth.onAuthStateChange((_event,next)=>{const token=next?.access_token||null;setSession(token);if(token)load(token);else setData(null)});return()=>subscription.unsubscribe()},[supabase,load]);
  if(!authReady)return <AdminLoader/>;
  if(!supabase&&process.env.NODE_ENV!=="development")return <AdminConfigurationRequired message={getSupabasePublicConfigError()}/>;
  if(supabase&&!session)return <AdminLogin onSuccess={token=>{setSession(token);load(token)}}/>;
  const demoData:AdminData={orders:[],reviews:[],coupons:[],shippingMethods:[],siteContent:defaultSiteContent,categories:[{id:"hair-care",name:"Үс арчилгаа",slug:"hair-care"},{id:"fashion",name:"Загвар",slug:"fashion"}],products:fallbackProducts.map((item,index)=>({id:item.id,name:item.name,slug:item.id,description:item.description,benefits:[item.benefit],price:item.price,stock:[34,12,46,8,23][index],is_active:true,is_featured:Boolean(item.badge),images:[item.image],category_id:item.category==="Үс арчилгаа"?"hair-care":"fashion"}))};
  const current=data||demoData;
  const nav=[[LayoutDashboard,"Хяналтын самбар"],[ShoppingBag,"Захиалга"],[Boxes,"Бүтээгдэхүүн"],[Settings,"Контент"]] as const;
  const selectTab=(name:string)=>{setTab(name);const path=name==="Бүтээгдэхүүн"?"/admin/products":name==="Захиалга"?"/admin/orders":name==="Контент"?"/admin/content":"/admin";window.history.replaceState(null,"",path)};
  return <main className="min-h-screen bg-[#f5f5f3] text-ink">
    <aside className="fixed inset-y-0 left-0 hidden w-64 border-r border-black/5 bg-white p-5 lg:block"><Link href="/" className="text-xl font-black tracking-tighter">TOMOC<span className="text-gold">.</span> <span className="text-xs font-semibold text-neutral-400">ADMIN</span></Link><nav className="mt-10 space-y-1">{nav.map(([Icon,name])=><button key={name} onClick={()=>selectTab(name)} className={`flex w-full items-center gap-3 rounded-xl px-3 py-3 text-sm font-semibold ${tab===name?"bg-ink text-white":"hover:bg-cloud"}`}><Icon size={18}/>{name}</button>)}</nav><Link href="/" className="absolute bottom-6 left-5 right-5 rounded-xl bg-cloud px-4 py-3 text-center text-sm font-bold">← Дэлгүүр рүү буцах</Link></aside>
    <div className="lg:pl-64"><header className="flex h-20 items-center justify-between border-b border-black/5 bg-white px-5 md:px-8"><div><p className="text-xs text-neutral-400">TOMOC STORE</p><h1 className="text-lg font-bold">{tab}</h1></div><div className="flex items-center gap-2"><button onClick={()=>load(session)} disabled={!session||loading} className="grid h-10 w-10 place-items-center rounded-full bg-cloud" aria-label="Шинэчлэх"><RefreshCw size={17} className={loading?"animate-spin":""}/></button>{supabase&&<button onClick={()=>supabase.auth.signOut()} className="grid h-10 w-10 place-items-center rounded-full bg-cloud" aria-label="Гарах"><LogOut size={17}/></button>}<div className="grid h-10 w-10 place-items-center rounded-full bg-[#dfc5aa] font-bold">T</div></div></header>
      <div className="hide-scroll flex gap-2 overflow-x-auto border-b border-black/5 bg-white px-4 pb-3 lg:hidden">{nav.slice(0,4).map(([Icon,name])=><button key={name} onClick={()=>selectTab(name)} className={`flex shrink-0 items-center gap-2 rounded-full px-4 py-2 text-xs font-bold ${tab===name?"bg-ink text-white":"bg-cloud"}`}><Icon size={15}/>{name}</button>)}</div>
      <div className="p-4 md:p-8">{!supabase&&<SetupBanner/>}{error&&<div role="alert" className="mb-5 rounded-2xl bg-red-50 p-4 text-sm text-red-700">{error}</div>}{tab==="Бүтээгдэхүүн"?<ProductsTableV2 products={current.products} categories={current.categories} token={session} onSaved={()=>load(session)}/>:tab==="Захиалга"?<OrdersTable orders={current.orders} token={session} onSaved={()=>load(session)}/>:tab==="Контент"?<ContentPanel content={current.siteContent||defaultSiteContent} token={session} onSaved={()=>load(session)}/>:tab==="Сэтгэгдэл"?<ReviewsTable reviews={current.reviews||[]} token={session} onSaved={()=>load(session)}/>:tab==="Ангилал ба купон"?<CommercePanel coupons={current.coupons||[]} shippingMethods={current.shippingMethods||[]} token={session} onSaved={()=>load(session)}/>:<Dashboard data={current}/>}</div>
    </div>
  </main>;
}

function AdminLoader(){return <main className="grid min-h-screen place-items-center bg-cloud"><LoaderCircle className="animate-spin"/></main>}
function AdminConfigurationRequired({message}:{message?:string|null}){return <main className="grid min-h-screen place-items-center bg-[#f2eee8] p-5"><div className="max-w-md rounded-[30px] bg-white p-8 text-center shadow-soft"><b className="text-xl">TOMOC<span className="text-gold">.</span></b><h1 className="display-serif mt-8 text-4xl">Admin тохиргоо шаардлагатай</h1><p className="mt-4 text-sm leading-6 text-neutral-500">{message||"Supabase environment variables тохируулаагүй үед production admin хаалттай байна."}</p><Link href="/" className="btn btn-black mt-6">Дэлгүүр рүү буцах</Link></div></main>}
function SetupBanner(){return <div className="mb-6 rounded-2xl border border-amber-200 bg-amber-50 p-4 text-sm text-amber-900"><b>Demo горим</b><p className="mt-1">Supabase environment variables нэмсний дараа нэвтрэлт, live бүтээгдэхүүн болон захиалга автоматаар идэвхжинэ.</p></div>}

function AdminLogin({onSuccess}:{onSuccess:(token:string)=>void}){const supabase=getSupabase()!;const [email,setEmail]=useState("");const [password,setPassword]=useState("");const [error,setError]=useState("");const [loading,setLoading]=useState(false);const friendlyError=(message?:string)=>message?.toLowerCase().includes("invalid api key")?"Vercel дээр Supabase тохиргоо буруу байна. NEXT_PUBLIC_SUPABASE_URL болон NEXT_PUBLIC_SUPABASE_ANON_KEY-г шалгана уу.":message||"Нэвтэрч чадсангүй.";const submit=async(event:React.FormEvent)=>{event.preventDefault();setLoading(true);setError("");const configError=getSupabasePublicConfigError();if(configError){setLoading(false);return setError(configError)}const {data,error}=await supabase.auth.signInWithPassword({email,password});setLoading(false);if(error||!data.session)return setError(friendlyError(error?.message));onSuccess(data.session.access_token)};return <main className="grid min-h-screen place-items-center bg-[#f2eee8] p-5"><form onSubmit={submit} className="w-full max-w-md rounded-[30px] bg-white p-8 shadow-soft"><Link href="/" className="text-xl font-black">TOMOC<span className="text-gold">.</span></Link><p className="eyebrow mt-10">ADMIN ACCESS</p><h1 className="display-serif mt-2 text-4xl">Удирдлагын хэсэг</h1><p className="mt-3 text-sm text-neutral-500">Зөвхөн admin эрхтэй бүртгэлээр нэвтэрнэ.</p><div className="mt-7 space-y-3"><input required type="email" className="input" placeholder="И-мэйл" value={email} onChange={event=>setEmail(event.target.value)}/><input required type="password" className="input" placeholder="Нууц үг" value={password} onChange={event=>setPassword(event.target.value)}/></div>{error&&<p className="mt-3 text-sm text-red-600">{error}</p>}<button disabled={loading} className="btn btn-black mt-5 w-full">{loading?"Нэвтэрч байна...":"Нэвтрэх"}</button><Link href="/" className="mt-5 block text-center text-sm font-bold">← Дэлгүүр рүү буцах</Link></form></main>}

function Dashboard({data}:{data:AdminData}){const actions=[["Бараа нэмэх","/admin/products",Plus,`Нийт ${data.products.length} бараа`],["Бараа засах","/admin/products",Boxes,"Үнэ, зураг, үлдэгдэл засах"],["Захиалга харах","/admin/orders",ShoppingBag,`Нийт ${data.orders.length} захиалга`],["Нүүр хуудас засах","/admin/content",Settings,"Гарчиг, зураг, холбоо барих"] ] as const;return <section className="rounded-3xl bg-white p-6"><p className="eyebrow">TOMOC STORE ADMIN</p><h2 className="mt-2 text-3xl font-bold tracking-tight">Юу хийх вэ?</h2><p className="mt-2 text-sm text-neutral-500">Бараа нэмэх, засах, захиалгаа харахад хэрэгтэй үндсэн хэсгүүд.</p><div className="mt-7 grid gap-4 md:grid-cols-2">{actions.map(([label,href,Icon,desc])=><Link key={label} href={href} className="group rounded-3xl bg-cloud p-6 transition hover:-translate-y-1 hover:bg-ink hover:text-white"><div className="grid h-12 w-12 place-items-center rounded-2xl bg-white text-ink"><Icon size={22}/></div><b className="mt-6 block text-2xl">{label}</b><p className="mt-2 text-sm opacity-70">{desc}</p></Link>)}</div></section>}
function Metric({icon:Icon,label,value}:{icon:typeof Package,label:string,value:string}){return <div className="rounded-3xl bg-white p-5"><div className="grid h-10 w-10 place-items-center rounded-xl bg-cloud"><Icon size={19}/></div><p className="mt-5 text-xs text-neutral-400">{label}</p><b className="mt-1 block text-2xl tracking-tight">{value}</b></div>}

function OrdersTable({orders,token,onSaved}:{orders:LiveOrder[],token:string|null,onSaved?:()=>void}){const update=async(id:string,status:string)=>{if(!token)return;const response=await fetch("/api/admin",{method:"PATCH",headers:{"content-type":"application/json",authorization:`Bearer ${token}`},body:JSON.stringify({resource:"orders",id,status})});if(response.ok&&status==="refunded"){const order=orders.find(item=>item.id===id);if(order)trackEvent("refund",{transaction_id:order.order_number,value:order.total,currency:"MNT"},{dedupeKey:`refund:${order.order_number}`,oncePerSession:true})}onSaved?.()};const address=(order:LiveOrder)=>[order.shipping_address?.location,order.shipping_address?.address].filter(Boolean).join(" • ")||"Хаяг ороогүй";return <div className="overflow-auto rounded-3xl bg-white"><table className="w-full min-w-[1100px] text-left text-sm"><thead className="bg-cloud text-xs text-neutral-500"><tr><th className="px-6 py-3">Дугаар</th><th>Хэрэглэгч</th><th>Утас</th><th>Хаяг</th><th>Бараа</th><th>Дүн</th><th>Төлбөр</th><th>Төлөв</th></tr></thead><tbody>{orders.length?orders.map(order=><tr key={order.id} className="border-t border-black/5 align-top"><td className="px-6 py-4"><b>{order.order_number}</b><p className="mt-1 text-xs text-neutral-400">{new Intl.DateTimeFormat("mn-MN",{dateStyle:"medium"}).format(new Date(order.created_at))}</p></td><td className="py-4 font-bold">{order.customer_name}</td><td className="py-4">{order.phone}</td><td className="max-w-[220px] py-4 text-xs leading-5 text-neutral-600">{address(order)}</td><td className="max-w-[260px] py-4 text-xs leading-5">{order.order_items?.length?order.order_items.map(item=><div key={`${order.id}-${item.product_name}`}>{item.product_name} × {item.quantity}</div>):"Бараа алга"}</td><td className="py-4 font-bold">{money(order.total)}</td><td className="py-4"><span className={`rounded-full px-3 py-1.5 text-xs font-bold ${order.payment_status==="paid"?"bg-green-100 text-green-700":order.payment_status==="failed"?"bg-red-100 text-red-700":"bg-amber-100 text-amber-800"}`}>{order.payment_status}</span></td><td className="py-4">{token?<select value={order.status} onChange={event=>update(order.id,event.target.value)} className="rounded-full bg-cloud px-3 py-2 text-xs font-bold">{Object.entries(statusLabels).map(([value,label])=><option key={value} value={value}>{label}</option>)}</select>:<span className="rounded-full bg-amber-100 px-3 py-1.5 text-xs font-bold text-amber-800">{statusLabels[order.status]||order.status}</span>}</td></tr>):<tr><td colSpan={8} className="px-6 py-14 text-center text-neutral-400">Захиалга одоогоор байхгүй.</td></tr>}</tbody></table></div>}

function ContentPanel({content,token,onSaved}:{content:SiteContent;token:string|null;onSaved:()=>void|Promise<void>}){
  const [form,setForm]=useState<SiteContent>(content);
  const [busy,setBusy]=useState(false);
  const [message,setMessage]=useState("");
  const [error,setError]=useState("");
  const [uploadingAsset,setUploadingAsset]=useState<keyof SiteContent|null>(null);
  useEffect(()=>setForm(content),[content]);
  const change=(field:keyof SiteContent,value:string|boolean|SiteContent["faqItems"])=>setForm(current=>({...current,[field]:value}));
  const faqChange=(index:number,field:"question"|"answer",value:string)=>change("faqItems",form.faqItems.map((item,i)=>i===index?{...item,[field]:value}:item));
  const imageFields:{field:keyof SiteContent;label:string;optional?:boolean}[]=[
    {field:"heroImage",label:"Hero зураг"},
    {field:"signatureImage",label:"Signature зураг"},
    {field:"aboutImage",label:"About зураг"},
    {field:"beforeImage",label:"Өмнөх зураг"},
    {field:"afterImage",label:"Дараах зураг"},
    {field:"mobileHeroImage",label:"Mobile Hero зураг",optional:true},
    {field:"socialShareImage",label:"Social share зураг",optional:true},
  ];
  const isDirectImageUrl=(value:string)=>{
    const url=value.trim();
    if(!url)return true;
    if(url.startsWith("/images/")||url.startsWith("/products/"))return true;
    if(/^https:\/\/.+\.(jpe?g|png|webp)(\?.*)?$/i.test(url))return true;
    if(/^https:\/\/.+\.supabase\.co\/storage\/v1\/object\/public\/.+/i.test(url))return true;
    return false;
  };
  const updateImageUrl=(field:keyof SiteContent,value:string)=>{
    setError("");
    change(field,value);
  };
  const uploadSiteAsset=async(field:keyof SiteContent,files:FileList|null)=>{
    const file=files?.[0];
    if(!token)return setError("Нэвтрэх шаардлагатай.");
    if(!file)return setError("Зураг сонгоно уу");
    if(!imageUploadTypes.has(file.type))return setError("Зөвхөн JPG, PNG, WEBP зураг оруулна уу");
    if(file.size>5*1024*1024)return setError("Зураг 5MB-аас их байна");
    setUploadingAsset(field);setError("");setMessage("");
    try{
      const payload=new FormData();payload.append("file",file);
      const response=await fetch("/api/admin/site-assets",{method:"POST",headers:{authorization:`Bearer ${token}`},body:payload});
      const result=await response.json().catch(()=>({success:false,error:"Серверээс буруу хариу ирлээ."}));
      if(!response.ok||result.success===false||!result.url)throw new Error(result.error||"Зураг upload хийхэд алдаа гарлаа");
      change(field,result.url);
      setMessage("Зураг амжилттай upload хийгдлээ");
    }catch(cause){setError(cause instanceof Error?cause.message:"Зураг upload хийхэд алдаа гарлаа")}
    finally{setUploadingAsset(null)}
  };
  const save=async()=>{if(!token)return;setBusy(true);setError("");setMessage("");try{const response=await fetch("/api/admin",{method:"PATCH",headers:{"content-type":"application/json",authorization:`Bearer ${token}`},body:JSON.stringify({resource:"site_content",content:form})});const result=await response.json().catch(()=>({success:false,error:"Серверээс буруу хариу ирлээ."}));if(!response.ok||result.success===false)throw new Error(result.error||"Контент хадгалахад алдаа гарлаа");if(result.content)setForm(result.content);await Promise.resolve(onSaved());setMessage("Контент амжилттай хадгалагдлаа")}catch(cause){setError(cause instanceof Error?cause.message:"Контент хадгалахад алдаа гарлаа")}finally{setBusy(false)}};
  return <section className="space-y-6">
    <div className="rounded-3xl bg-white p-6"><p className="eyebrow">HOMEPAGE CMS</p><h2 className="mt-2 text-2xl font-bold">Нүүр хуудасны текст засах</h2><p className="mt-2 text-sm text-neutral-500">Энд хадгалсан текст болон зураг customer-facing нүүр хуудсанд автоматаар харагдана.</p><p className="mt-4 rounded-xl bg-cloud p-3 text-xs text-neutral-500">Одоогийн Hero title: <b className="text-ink">{form.heroTitle}</b></p>{message&&<p role="status" className="mt-4 rounded-xl bg-green-50 p-3 text-sm font-bold text-green-700">{message}</p>}{error&&<p role="alert" className="mt-4 rounded-xl bg-red-50 p-3 text-sm text-red-700">{error}</p>}</div>
    <div className="grid gap-5 lg:grid-cols-2">
      <ContentCard title="Hero хэсэг"><TextInput label="Hero eyebrow" value={form.heroEyebrow} onChange={value=>change("heroEyebrow",value)}/><TextInput label="Hero title" value={form.heroTitle} onChange={value=>change("heroTitle",value)} textarea/><TextInput label="Hero subtitle" value={form.heroSubtitle} onChange={value=>change("heroSubtitle",value)} textarea/><TextInput label="Primary CTA text" value={form.primaryCtaText} onChange={value=>change("primaryCtaText",value)}/></ContentCard>
      <ContentCard title="Signature / About"><TextInput label="Signature title" value={form.signatureTitle} onChange={value=>change("signatureTitle",value)} textarea/><TextInput label="Signature subtitle" value={form.signatureSubtitle} onChange={value=>change("signatureSubtitle",value)} textarea/><TextInput label="About title" value={form.aboutTitle} onChange={value=>change("aboutTitle",value)} textarea/><TextInput label="About body" value={form.aboutBody} onChange={value=>change("aboutBody",value)} textarea/></ContentCard>
      <ContentCard title="Нүүр хуудасны зураг"><div className="grid gap-4">{imageFields.map(item=>{const value=String(form[item.field]||"");const isUploading=uploadingAsset===item.field;const hasInvalidImage=Boolean(value&&!isDirectImageUrl(value));return <div key={String(item.field)} className="rounded-2xl border border-black/5 bg-cloud p-4"><div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between"><div className="min-w-0"><b className="text-sm">{item.label}</b>{item.optional&&<span className="ml-2 rounded-full bg-white px-2 py-1 text-[10px] font-bold text-neutral-500">optional</span>}<p className="mt-1 text-xs text-neutral-500">JPG, PNG, WEBP • 5MB хүртэл</p></div><div className="flex shrink-0 flex-wrap gap-2"><input id={`site-asset-${String(item.field)}`} type="file" accept="image/jpeg,image/png,image/webp" className="hidden" onChange={event=>{uploadSiteAsset(item.field,event.target.files);event.currentTarget.value=""}}/><label htmlFor={`site-asset-${String(item.field)}`} className={`btn h-10 cursor-pointer text-xs ${isUploading?"bg-neutral-300 text-neutral-600":"btn-black"}`}>{isUploading?<><LoaderCircle className="animate-spin" size={15}/> Upload...</>:value?"Зураг солих":"Зураг upload хийх"}</label>{value&&<button type="button" onClick={()=>change(item.field,"")} className="btn h-10 bg-white px-4 text-xs">Зураг арилгах</button>}</div></div>{isUploading&&<div className="mt-4 max-w-[320px] rounded-full bg-white p-1"><div className="h-2 w-2/3 animate-pulse rounded-full bg-ink"/><p className="mt-2 text-xs font-bold text-neutral-500">Зураг upload хийж байна...</p></div>}{value?<div className="mt-4 max-w-[320px] rounded-2xl border border-black/10 bg-white p-2 shadow-sm">{hasInvalidImage?<div className="grid h-36 place-items-center rounded-xl bg-amber-50 px-4 text-center text-xs font-bold leading-5 text-amber-800">Энэ зурагны холбоос биш байна. Шинэ зураг upload хийнэ үү.</div>:<div className="h-44 overflow-hidden rounded-xl bg-cloud"><img src={value} alt={item.label} className="h-full w-full object-cover" onError={event=>{event.currentTarget.style.display="none"}}/></div>}<details className="mt-2"><summary className="cursor-pointer text-[11px] font-bold text-neutral-500">Зурагны холбоос харах</summary><p className="mt-1 max-w-[280px] break-all rounded-xl bg-cloud p-2 text-[11px] leading-4 text-neutral-500">{value}</p></details></div>:<div className="mt-4 grid h-36 max-w-[320px] place-items-center rounded-2xl border border-dashed border-black/10 bg-white px-4 text-center text-sm font-bold text-neutral-400">Зураг сонгоно уу</div>}<details className="mt-3 max-w-[420px]"><summary className="cursor-pointer text-xs font-bold">Нарийвчилсан тохиргоо</summary><input className="input mt-2" value={value} placeholder="/images/tomoc-hero.png эсвэл Supabase image URL" onChange={event=>updateImageUrl(item.field,event.target.value)}/><span className="mt-1 block text-[11px] text-neutral-500">Энэ хэсгийг зөвхөн шаардлагатай үед ашиглана. Энгийн үед дээрх upload товчийг дарж зураг солино.</span></details></div>})}</div></ContentCard>
      <ContentCard title="Хүргэлт ба холбоо барих"><TextInput label="Delivery text" value={form.deliveryText} onChange={value=>change("deliveryText",value)} textarea/><TextInput label="Contact phone" value={form.contactPhone} onChange={value=>change("contactPhone",value)}/><TextInput label="WhatsApp number" value={form.whatsappNumber} onChange={value=>change("whatsappNumber",value)}/><TextInput label="Messenger text" value={form.messengerText} onChange={value=>change("messengerText",value)}/><TextInput label="Messenger URL" value={form.messengerUrl} onChange={value=>change("messengerUrl",value)}/><TextInput label="Footer description" value={form.footerDescription} onChange={value=>change("footerDescription",value)} textarea/><label className="mt-3 flex items-center gap-2 rounded-xl bg-cloud px-4 py-3 text-sm font-bold"><input type="checkbox" checked={form.testimonialsEnabled} onChange={event=>change("testimonialsEnabled",event.target.checked)}/> Сэтгэгдлийн placeholder хэсгийг харуулах</label></ContentCard>
      <ContentCard title="FAQ"><div className="space-y-4">{form.faqItems.map((item,index)=><div key={index} className="rounded-2xl bg-cloud p-3"><TextInput label={`Асуулт ${index+1}`} value={item.question} onChange={value=>faqChange(index,"question",value)}/><TextInput label={`Хариулт ${index+1}`} value={item.answer} onChange={value=>faqChange(index,"answer",value)} textarea/></div>)}</div></ContentCard>
    </div>
    <div className="sticky bottom-4 rounded-3xl bg-white p-4 shadow-soft"><button disabled={busy||!token} onClick={save} className="btn btn-black w-full disabled:opacity-40">{busy?"Хадгалж байна...":"Контент хадгалах"}</button></div>
  </section>
}
function ContentCard({title,children}:{title:string;children:React.ReactNode}){return <div className="rounded-3xl bg-white p-5"><h3 className="font-bold">{title}</h3><div className="mt-4 space-y-3">{children}</div></div>}
function TextInput({label,value,onChange,textarea=false}:{label:string;value:string;onChange:(value:string)=>void;textarea?:boolean}){return <label className="block text-xs font-bold">{label}{textarea?<textarea className="input mt-1 min-h-24 py-3" value={value} onChange={event=>onChange(event.target.value)}/>:<input className="input mt-1" value={value} onChange={event=>onChange(event.target.value)}/>}</label>}

function ReviewsTable({reviews,token,onSaved}:{reviews:LiveReview[],token:string|null,onSaved:()=>void}){const [busy,setBusy]=useState("");const [error,setError]=useState("");const moderate=async(id:string,status:"approved"|"rejected")=>{if(!token)return;setBusy(id);setError("");try{const response=await fetch("/api/admin",{method:"PATCH",headers:{"content-type":"application/json",authorization:`Bearer ${token}`},body:JSON.stringify({resource:"reviews",id,status})});const result=await response.json();if(!response.ok)throw new Error(result.error||"Төлөв шинэчилж чадсангүй.");onSaved()}catch(cause){setError(cause instanceof Error?cause.message:"Алдаа гарлаа.")}finally{setBusy("")}};const remove=async(id:string)=>{if(!token||!window.confirm("Энэ сэтгэгдлийг бүрмөсөн устгах уу?"))return;setBusy(id);try{const response=await fetch(`/api/admin?resource=reviews&id=${encodeURIComponent(id)}`,{method:"DELETE",headers:{authorization:`Bearer ${token}`}});if(!response.ok)throw new Error("Устгаж чадсангүй.");onSaved()}catch(cause){setError(cause instanceof Error?cause.message:"Алдаа гарлаа.")}finally{setBusy("")}};return <section className="overflow-hidden rounded-3xl bg-white"><div className="p-6"><h2 className="font-bold">Сэтгэгдлийн moderation</h2><p className="mt-1 text-xs text-neutral-400">{reviews.filter(review=>review.moderation_status==="pending").length} хүлээгдэж буй • нийт {reviews.length}</p></div>{error&&<p role="alert" className="mx-6 mb-4 rounded-xl bg-red-50 p-3 text-sm text-red-700">{error}</p>}<div className="divide-y divide-black/5">{reviews.length?reviews.map(review=>{const product=Array.isArray(review.products)?review.products[0]?.name:review.products?.name;return <article key={review.id} className="grid gap-5 p-6 lg:grid-cols-[1fr_auto] lg:items-center"><div><div className="flex flex-wrap items-center gap-3"><b>{review.customer_name}</b><span className="flex text-gold">{[1,2,3,4,5].map(star=><Star key={star} size={14} fill={star<=review.rating?"currentColor":"none"}/>)}</span>{review.is_verified&&<span className="inline-flex items-center gap-1 rounded-full bg-green-50 px-2 py-1 text-[10px] font-bold text-green-700"><BadgeCheck size={13}/> Баталгаажсан</span>}<span className={`rounded-full px-2 py-1 text-[10px] font-bold ${review.moderation_status==="approved"?"bg-green-50 text-green-700":review.moderation_status==="rejected"?"bg-red-50 text-red-700":"bg-amber-50 text-amber-800"}`}>{review.moderation_status}</span></div><p className="mt-2 text-xs font-bold text-neutral-400">{product||"Бүтээгдэхүүн"} • {new Intl.DateTimeFormat("mn-MN",{dateStyle:"medium"}).format(new Date(review.created_at))}</p>{review.title&&<h3 className="mt-3 font-bold">{review.title}</h3>}<p className="mt-2 max-w-3xl text-sm leading-6 text-neutral-600">{review.body}</p></div><div className="flex gap-2"><button disabled={busy===review.id} onClick={()=>moderate(review.id,"approved")} aria-label="Нийтлэх" className="grid h-10 w-10 place-items-center rounded-full bg-green-50 text-green-700 disabled:opacity-40"><Check size={17}/></button><button disabled={busy===review.id} onClick={()=>moderate(review.id,"rejected")} aria-label="Татгалзах" className="grid h-10 w-10 place-items-center rounded-full bg-amber-50 text-amber-800 disabled:opacity-40"><X size={17}/></button><button disabled={busy===review.id} onClick={()=>remove(review.id)} aria-label="Устгах" className="grid h-10 w-10 place-items-center rounded-full bg-red-50 text-red-700 disabled:opacity-40"><Trash2 size={17}/></button></div></article>}):<div className="py-16 text-center text-sm text-neutral-400">Сэтгэгдэл одоогоор алга.</div>}</div></section>}

function CommercePanel({coupons,shippingMethods,token,onSaved}:{coupons:Coupon[];shippingMethods:ShippingMethod[];token:string|null;onSaved:()=>void}){
  const blank:Coupon={id:"",code:"",discount_type:"percent",discount_value:10,min_order:0,max_uses:null,used_count:0,starts_at:new Date().toISOString(),expires_at:null,single_use:false,is_active:true};
  const [editing,setEditing]=useState<(Coupon&{isNew?:boolean})|null>(null),[busy,setBusy]=useState(false),[error,setError]=useState("");const save=async()=>{if(!token||!editing)return;setBusy(true);setError("");try{const response=await fetch("/api/admin",{method:editing.isNew?"POST":"PATCH",headers:{"content-type":"application/json",authorization:`Bearer ${token}`},body:JSON.stringify({...editing,resource:"coupons"})});const result=await response.json();if(!response.ok)throw new Error(result.error||"Купон хадгалж чадсангүй.");setEditing(null);onSaved()}catch(cause){setError(cause instanceof Error?cause.message:"Алдаа гарлаа.")}finally{setBusy(false)}};const remove=async(id:string)=>{if(!token||!window.confirm("Купоныг устгах уу?"))return;const response=await fetch(`/api/admin?resource=coupons&id=${encodeURIComponent(id)}`,{method:"DELETE",headers:{authorization:`Bearer ${token}`}});if(response.ok)onSaved();else setError("Ашиглагдсан купоныг устгах боломжгүй байж болно. Идэвхгүй болгоно уу.")};return <div className="space-y-6"><section className="overflow-hidden rounded-3xl bg-white"><div className="flex items-center justify-between p-6"><div><h2 className="font-bold">Купоны удирдлага</h2><p className="mt-1 text-xs text-neutral-400">Нийт {coupons.length} купон</p></div><button disabled={!token} onClick={()=>setEditing({...blank,isNew:true})} className="btn btn-black h-10 text-sm"><Plus size={16}/> Купон үүсгэх</button></div>{error&&<p role="alert" className="mx-6 mb-4 rounded-xl bg-red-50 p-3 text-sm text-red-700">{error}</p>}<div className="overflow-auto"><table className="w-full min-w-[760px] text-left text-sm"><thead className="bg-cloud text-xs text-neutral-500"><tr><th className="px-6 py-3">Код</th><th>Хөнгөлөлт</th><th>Доод дүн</th><th>Ашиглалт</th><th>Хугацаа</th><th></th></tr></thead><tbody>{coupons.length?coupons.map(coupon=><tr key={coupon.id} className="border-t border-black/5"><td className="px-6 py-4"><b>{coupon.code}</b><p className={`text-[10px] font-bold ${coupon.is_active?"text-green-600":"text-neutral-400"}`}>{coupon.is_active?"ИДЭВХТЭЙ":"ИДЭВХГҮЙ"}{coupon.single_use?" • НЭГ УДАА":""}</p></td><td>{coupon.discount_type==="percent"?`${coupon.discount_value}%`:money(coupon.discount_value)}</td><td>{money(coupon.min_order)}</td><td>{coupon.used_count}/{coupon.max_uses??"∞"}</td><td>{coupon.expires_at?new Intl.DateTimeFormat("mn-MN",{dateStyle:"medium"}).format(new Date(coupon.expires_at)):"Хугацаагүй"}</td><td><div className="flex gap-3"><button onClick={()=>setEditing({...coupon,starts_at:coupon.starts_at||new Date().toISOString()})} className="font-bold">Засах</button><button onClick={()=>remove(coupon.id)} className="text-red-600" aria-label={`${coupon.code} устгах`}><Trash2 size={16}/></button></div></td></tr>):<tr><td colSpan={6} className="px-6 py-14 text-center text-neutral-400">Купон одоогоор алга.</td></tr>}</tbody></table></div>{editing&&<div className="border-t border-black/10 bg-cloud p-6"><div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3"><label className="text-xs font-bold">Код<input disabled={!editing.isNew} className="input mt-1 uppercase disabled:opacity-60" value={editing.code} onChange={e=>setEditing({...editing,code:e.target.value.toUpperCase()})}/></label><label className="text-xs font-bold">Төрөл<select className="input mt-1" value={editing.discount_type} onChange={e=>setEditing({...editing,discount_type:e.target.value as "percent"|"fixed"})}><option value="percent">Хувь</option><option value="fixed">Тогтмол дүн</option></select></label><label className="text-xs font-bold">Хөнгөлөлт<input type="number" min="1" className="input mt-1" value={editing.discount_value} onChange={e=>setEditing({...editing,discount_value:Number(e.target.value)})}/></label><label className="text-xs font-bold">Доод худалдан авалт<input type="number" min="0" className="input mt-1" value={editing.min_order} onChange={e=>setEditing({...editing,min_order:Number(e.target.value)})}/></label><label className="text-xs font-bold">Ашиглах хязгаар<input type="number" min="1" className="input mt-1" placeholder="Хязгааргүй" value={editing.max_uses??""} onChange={e=>setEditing({...editing,max_uses:e.target.value?Number(e.target.value):null})}/></label><label className="text-xs font-bold">Дуусах огноо<input type="datetime-local" className="input mt-1" value={editing.expires_at?editing.expires_at.slice(0,16):""} onChange={e=>setEditing({...editing,expires_at:e.target.value?new Date(e.target.value).toISOString():null})}/></label></div><div className="mt-4 flex flex-wrap gap-3"><label className="flex items-center gap-2 rounded-xl bg-white px-4 py-3 text-sm font-bold"><input type="checkbox" checked={editing.single_use} onChange={e=>setEditing({...editing,single_use:e.target.checked})}/> Хэрэглэгч бүр нэг удаа</label><label className="flex items-center gap-2 rounded-xl bg-white px-4 py-3 text-sm font-bold"><input type="checkbox" checked={editing.is_active} onChange={e=>setEditing({...editing,is_active:e.target.checked})}/> Идэвхтэй</label></div><div className="mt-5 flex gap-2"><button disabled={busy||!editing.code} onClick={save} className="btn btn-black">{busy?"Хадгалж байна...":"Хадгалах"}</button><button onClick={()=>setEditing(null)} className="btn bg-white">Болих</button></div></div>}</section><ShippingAdmin methods={shippingMethods}/></div>}

function ShippingAdmin({methods}:{methods:ShippingMethod[]}){const [items,setItems]=useState(methods),[busy,setBusy]=useState(""),[message,setMessage]=useState("");useEffect(()=>setItems(methods),[methods]);const change=(id:string,field:keyof ShippingMethod,value:unknown)=>setItems(current=>current.map(item=>item.id===id?{...item,[field]:value}:item));const save=async(method:ShippingMethod)=>{const supabase=getSupabase(),session=(await supabase?.auth.getSession())?.data.session;if(!session)return;setBusy(method.id);setMessage("");try{const response=await fetch("/api/admin",{method:"PATCH",headers:{"content-type":"application/json",authorization:`Bearer ${session.access_token}`},body:JSON.stringify({...method,resource:"shipping_methods"})});const result=await response.json();if(!response.ok)throw new Error(result.error||"Хадгалж чадсангүй.");setMessage(`${method.name} хадгалагдлаа.`)}catch(cause){setMessage(cause instanceof Error?cause.message:"Алдаа гарлаа.")}finally{setBusy("")}};return <section className="rounded-3xl bg-white p-6"><h2 className="font-bold">Хүргэлтийн тохиргоо</h2><p className="mt-1 text-xs text-neutral-400">Үнэ, үнэгүй хүргэлтийн босго, тооцоолсон хугацааг удирдана.</p>{message&&<p role="status" className="mt-4 rounded-xl bg-cloud p-3 text-sm">{message}</p>}<div className="mt-5 grid gap-4 xl:grid-cols-3">{items.map(method=><div key={method.id} className="rounded-2xl bg-cloud p-4"><div className="flex items-center justify-between gap-3"><b>{method.name}</b><label className="text-xs font-bold"><input type="checkbox" className="mr-2" checked={method.is_active} onChange={e=>change(method.id,"is_active",e.target.checked)}/>Идэвхтэй</label></div><div className="mt-4 space-y-3"><label className="block text-[11px] font-bold">Үндсэн үнэ<input type="number" min="0" disabled={method.method_type==="pickup"} className="input mt-1" value={method.flat_rate} onChange={e=>change(method.id,"flat_rate",Number(e.target.value))}/></label><label className="block text-[11px] font-bold">Үнэгүй хүргэлтийн босго<input type="number" min="0" disabled={method.method_type==="pickup"} className="input mt-1" placeholder="Босгогүй" value={method.free_shipping_threshold??""} onChange={e=>change(method.id,"free_shipping_threshold",e.target.value?Number(e.target.value):null)}/></label><div className="grid grid-cols-2 gap-2"><label className="text-[11px] font-bold">Мин. өдөр<input type="number" min="0" className="input mt-1" value={method.estimated_min_days} onChange={e=>change(method.id,"estimated_min_days",Number(e.target.value))}/></label><label className="text-[11px] font-bold">Макс. өдөр<input type="number" min="0" className="input mt-1" value={method.estimated_max_days} onChange={e=>change(method.id,"estimated_max_days",Number(e.target.value))}/></label></div><button onClick={()=>save(method)} disabled={busy===method.id} className="btn btn-black h-10 w-full text-xs disabled:opacity-50">{busy===method.id?"Хадгалж байна...":"Хадгалах"}</button></div></div>)}</div></section>}

function ProductsTable({products,categories,token,onSaved}:{products:LiveProduct[],categories:Category[],token:string|null,onSaved:()=>void|Promise<void>}){
  type ProductForm = LiveProduct & { isNew?: boolean; imageUrl: string };
  const categoryName=(id?:string|null)=>categories.find(category=>category.id===id)?.name||"Ангилалгүй";
  const emptyForm=():ProductForm=>({id:"",name:"",slug:"",description:"",benefits:[],price:0,stock:0,is_active:true,is_featured:false,images:[],imageUrl:"",category_id:categories[0]?.id||null,isNew:true});
  const toForm=(product:LiveProduct):ProductForm=>({...product,images:product.images||[],imageUrl:"",benefits:product.benefits||[],is_featured:Boolean(product.is_featured)});
  const [query,setQuery]=useState("");
  const [editing,setEditing]=useState<ProductForm|null>(null);
  const [busy,setBusy]=useState(false);
  const [message,setMessage]=useState("");
  const [error,setError]=useState("");
  const [imagePreviewErrors,setImagePreviewErrors]=useState<Record<string,boolean>>({});
  const [uploadingImage,setUploadingImage]=useState(false);
  const [uploadProgress,setUploadProgress]=useState(0);
  const imageInputRef=useRef<HTMLInputElement|null>(null);
  const filtered=useMemo(()=>products.filter(product=>`${product.name} ${product.slug}`.toLowerCase().includes(query.toLowerCase())),[products,query]);
  const startCreate=()=>{setError("");setMessage("");setImagePreviewErrors({});setEditing(emptyForm())};
  const startEdit=(product:LiveProduct)=>{setError("");setMessage("");setImagePreviewErrors({});setEditing(toForm(product))};
  const productImages=(form:ProductForm)=>Array.from(new Set((form.images||[]).map(url=>url.trim()).filter(Boolean))).slice(0,8);
  const setUrlInput=(value:string)=>setEditing(current=>current?{...current,imageUrl:value}:current);
  const appendImages=(urls:string[])=>setEditing(current=>{if(!current)return current;const next=Array.from(new Set([...(current.images||[]),...urls.map(url=>url.trim()).filter(Boolean)])).slice(0,8);return {...current,images:next}});
  const removeImage=(url:string)=>{setImagePreviewErrors(current=>{const next={...current};delete next[url];return next});setEditing(current=>current?{...current,images:(current.images||[]).filter(item=>item!==url)}:current)};
  const makeMainImage=(url:string)=>setEditing(current=>current?{...current,images:[url,...(current.images||[]).filter(item=>item!==url)]}:current);
  const moveImage=(index:number,direction:-1|1)=>setEditing(current=>{if(!current)return current;const images=productImages(current);const nextIndex=index+direction;if(nextIndex<0||nextIndex>=images.length)return current;const next=[...images];[next[index],next[nextIndex]]=[next[nextIndex],next[index]];return {...current,images:next}});
  const addUrlImage=()=>{if(!editing)return;const url=editing.imageUrl.trim();if(!url)return setError("Зураг сонгоно уу");if((editing.images||[]).length>=8)return setError("8-аас олон зураг оруулах боломжгүй");appendImages([url]);setUrlInput("");setError("")};
  const uploadImage=async(files:FileList|null)=>{const selected=Array.from(files||[]);if(imageInputRef.current)imageInputRef.current.value="";if(!token)return setError("Нэвтрэх шаардлагатай.");if(!selected.length)return setError("Зураг сонгоно уу");const currentCount=editing?.images?.length||0;if(currentCount+selected.length>8)return setError("8-аас олон зураг оруулах боломжгүй");const invalid=selected.find(file=>!imageUploadTypes.has(file.type));if(invalid)return setError("Зөвхөн JPG, PNG, WEBP зураг оруулна уу");const tooLarge=selected.find(file=>file.size>5*1024*1024);if(tooLarge)return setError("Зураг 5MB-аас их байна");setUploadingImage(true);setUploadProgress(10);setError("");setMessage("");try{const form=new FormData();selected.forEach(file=>form.append("files",file));setUploadProgress(35);const response=await fetch("/api/admin/upload",{method:"POST",headers:{authorization:`Bearer ${token}`},body:form});setUploadProgress(75);const result=await response.json().catch(()=>({success:false,error:"Серверээс буруу хариу ирлээ."}));if(!response.ok||result.success===false||!Array.isArray(result.urls)||!result.urls.length)throw new Error(result.error||"Зураг upload хийхэд алдаа гарлаа");appendImages(result.urls);setUploadProgress(100);setMessage("Зураг upload хийгдлээ. Бүтээгдэхүүнээ хадгална уу.")}catch(cause){setError(`Зураг upload хийхэд алдаа гарлаа${cause instanceof Error&&cause.message?`: ${cause.message}`:""}`)}finally{window.setTimeout(()=>{setUploadingImage(false);setUploadProgress(0)},350)}};
  const submit=async()=>{if(!token||!editing)return;setBusy(true);setError("");setMessage("");const name=editing.name.trim();const slug=productSlug(editing.slug,name);const price=Math.max(0,Math.round(Number(editing.price)||0));const stock=Math.max(0,Math.round(Number(editing.stock)||0));const finalImages=productImages(editing);try{if(!name)throw new Error("Нэр оруулна уу");if(price<=0)throw new Error("Үнэ зөв оруулна уу");if(!editing.category_id)throw new Error("Ангилал сонгоно уу");if(!finalImages.length)throw new Error("Зураг сонгоно уу");const payload={resource:"products",id:editing.id,name,slug,price,stock,category_id:editing.category_id,benefits:editing.benefits||[],description:editing.description||"",images:finalImages,is_active:Boolean(editing.is_active),is_featured:Boolean(editing.is_featured)};const response=await fetch("/api/admin",{method:editing.isNew?"POST":"PATCH",headers:{"content-type":"application/json",authorization:`Bearer ${token}`},body:JSON.stringify(payload)});const result=await response.json().catch(()=>({success:false,error:"Серверээс буруу хариу ирлээ."}));if(!response.ok||result.success===false)throw new Error(result.error||"Бүтээгдэхүүн хадгалахад алдаа гарлаа.");const successText=editing.isNew?"Бүтээгдэхүүн амжилттай нэмэгдлээ.":"Бүтээгдэхүүн амжилттай шинэчлэгдлээ.";setEditing(null);await Promise.resolve(onSaved());setMessage(successText)}catch(cause){setError(cause instanceof Error?cause.message:"Бүтээгдэхүүн хадгалахад алдаа гарлаа.")}finally{setBusy(false)}};
  const toggleActive=async(product:LiveProduct)=>{if(!token)return;setBusy(true);setError("");setMessage("");try{const response=await fetch("/api/admin",{method:"PATCH",headers:{"content-type":"application/json",authorization:`Bearer ${token}`},body:JSON.stringify({resource:"product_status",id:product.id,is_active:!product.is_active})});const result=await response.json().catch(()=>({success:false,error:"Серверээс буруу хариу ирлээ."}));if(!response.ok||result.success===false)throw new Error(result.error||"Бүтээгдэхүүний төлөв шинэчилж чадсангүй.");await Promise.resolve(onSaved());setMessage("Бүтээгдэхүүний төлөв шинэчлэгдлээ.")}catch(cause){setError(cause instanceof Error?cause.message:"Алдаа гарлаа.")}finally{setBusy(false)}};
  return <section className="overflow-hidden rounded-3xl bg-white"><style jsx global>{`[class~="border-t"][class~="bg-cloud"][class~="p-5"]>[class~="mt-5"][class~="grid"][class~="gap-4"]>label:nth-of-type(2){display:none}`}</style>
    <div className="flex flex-col justify-between gap-4 p-5 md:flex-row md:items-center md:p-6"><div><h2 className="font-bold">Бүтээгдэхүүний удирдлага</h2><p className="text-xs text-neutral-400">Нийт {products.length} бүтээгдэхүүн • Үүсгэх, засах, нуух/ил гаргах</p></div><div className="flex flex-col gap-2 sm:flex-row"><div className="relative"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400"/><input className="h-10 w-full rounded-xl bg-cloud pl-9 pr-4 text-sm outline-none" placeholder="Нэр эсвэл slug хайх" value={query} onChange={event=>setQuery(event.target.value)}/></div><button disabled={!token||busy} onClick={startCreate} className="btn btn-black h-10 text-sm disabled:opacity-40"><Plus size={16}/> Шинэ бүтээгдэхүүн</button></div></div>
    {error&&<div role="alert" className="mx-5 mb-4 rounded-xl bg-red-50 p-3 text-sm text-red-700">{error}</div>}{message&&<div role="status" className="mx-5 mb-4 rounded-xl bg-green-50 p-3 text-sm font-bold text-green-700">{message}</div>}
    <div className="overflow-auto"><table className="w-full min-w-[980px] text-left text-sm"><thead className="bg-cloud text-xs text-neutral-500"><tr><th className="px-6 py-3">Зураг</th><th>Нэр</th><th>Slug</th><th>Үнэ</th><th>Үлдэгдэл</th><th>Ангилал</th><th>Төлөв</th><th>Онцлох</th><th></th></tr></thead><tbody>{filtered.length?filtered.map(product=><tr key={product.id} className="border-t border-black/5"><td className="px-6 py-3"><div className="relative h-14 w-14 overflow-hidden rounded-xl bg-cloud"><Image src={product.images?.[0]||"/images/tomoc-beauty-campaign.png"} fill sizes="56px" className="object-cover" alt=""/></div></td><td className="font-bold">{product.name}</td><td className="max-w-[180px] truncate text-xs text-neutral-500">/{product.slug}</td><td className="font-bold">{money(product.price)}</td><td>{product.stock}</td><td>{categoryName(product.category_id)}</td><td><span className={`rounded-full px-3 py-1 text-xs font-bold ${product.is_active?"bg-green-100 text-green-700":"bg-neutral-100 text-neutral-500"}`}>{product.is_active?"Идэвхтэй":"Нуусан"}</span></td><td>{product.is_featured?"Тийм":"Үгүй"}</td><td><div className="flex gap-3"><button disabled={!token||busy} onClick={()=>startEdit(product)} className="font-bold disabled:text-neutral-300">Засах</button><button disabled={!token||busy} onClick={()=>toggleActive(product)} className={product.is_active?"text-red-600 disabled:text-neutral-300":"text-green-700 disabled:text-neutral-300"}>{product.is_active?"Нуух":"Ил гаргах"}</button></div></td></tr>):<tr><td colSpan={9} className="px-6 py-14 text-center text-neutral-400">Хайлтад тохирох бүтээгдэхүүн алга.</td></tr>}</tbody></table></div>
    {editing&&<div className="border-t border-black/10 bg-cloud p-5 md:p-7"><div className="flex items-center justify-between"><div><p className="eyebrow">{editing.isNew?"CREATE PRODUCT":"EDIT PRODUCT"}</p><h3 className="mt-1 text-xl font-bold">{editing.isNew?"Шинэ бүтээгдэхүүн":"Бүтээгдэхүүн засах"}</h3></div><button disabled={busy} onClick={()=>setEditing(null)} className="grid h-10 w-10 place-items-center rounded-full bg-white disabled:opacity-40" aria-label="Хаах"><X size={18}/></button></div><div className="mt-5 grid gap-4 lg:grid-cols-2"><label className="text-xs font-bold">Нэр<input className="input mt-1" value={editing.name} onChange={event=>setEditing({...editing,name:event.target.value})}/></label><label className="text-xs font-bold">Линк нэр / Slug<input className="input mt-1" value={editing.slug} placeholder="Хоосон бол автоматаар үүснэ" onChange={event=>setEditing({...editing,slug:event.target.value})}/></label><label className="text-xs font-bold">Үнэ<input inputMode="numeric" className="input mt-1" value={editing.price||""} placeholder="49900" onChange={event=>setEditing({...editing,price:normalizeWholeNumber(event.target.value)})}/></label><label className="text-xs font-bold">Үлдэгдэл<input inputMode="numeric" className="input mt-1" value={editing.stock||""} placeholder="10" onChange={event=>setEditing({...editing,stock:normalizeWholeNumber(event.target.value)})}/></label><label className="text-xs font-bold">Ангилал<select className="input mt-1" value={editing.category_id||""} onChange={event=>setEditing({...editing,category_id:event.target.value||null})}><option value="">Ангилал сонгох</option>{categories.map(category=><option key={category.id} value={category.id}>{category.name}</option>)}</select></label><div className="rounded-2xl bg-white p-4 lg:col-span-2"><div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between"><div><h4 className="text-sm font-black">Бүтээгдэхүүний зураг</h4><p className="mt-1 text-xs text-neutral-500">Нэг бүтээгдэхүүнд 8 хүртэл зураг upload хийнэ. Эхний зураг үндсэн зураг болно.</p><p className="mt-1 text-[11px] font-bold text-neutral-400">{productImages(editing).length}/8 зураг</p></div><div className="flex flex-wrap gap-2"><input ref={imageInputRef} type="file" multiple accept="image/jpeg,image/png,image/webp" className="hidden" onChange={event=>uploadImage(event.target.files)}/><button type="button" disabled={uploadingImage||busy||productImages(editing).length>=8} onClick={()=>imageInputRef.current?.click()} className="btn btn-black h-10 text-xs disabled:opacity-40">{uploadingImage?<><LoaderCircle className="animate-spin" size={15}/> Upload хийж байна...</>:"Зураг upload хийх"}</button></div></div>{uploadingImage&&<div className="mt-4 rounded-full bg-cloud p-1"><div className="h-2 rounded-full bg-ink transition-all" style={{width:`${uploadProgress}%`}}/><p className="mt-2 text-xs font-bold text-neutral-500">Зураг upload хийж байна... {uploadProgress}%</p></div>}{productImages(editing).length?<div className="mt-4 grid gap-3 sm:grid-cols-2 lg:grid-cols-4">{productImages(editing).map((url,index)=><div key={`${url}-${index}`} className="rounded-2xl bg-cloud p-2"><div className="relative h-32 overflow-hidden rounded-xl bg-white">{!imagePreviewErrors[url]?<img src={url} alt={`Бүтээгдэхүүний зураг ${index+1}`} className="h-full w-full object-cover" onLoad={()=>setImagePreviewErrors(current=>({...current,[url]:false}))} onError={()=>setImagePreviewErrors(current=>({...current,[url]:true}))}/>:<div className="grid h-full w-full place-items-center px-3 text-center text-[11px] font-bold text-red-600">Зураг харагдахгүй байна</div>}{index===0&&<span className="absolute left-2 top-2 rounded-full bg-ink px-2 py-1 text-[10px] font-bold text-white">Үндсэн зураг</span>}</div><p className="mt-2 truncate text-[11px] text-neutral-500">{url}</p><div className="mt-2 flex flex-wrap gap-2">{index>0&&<button type="button" onClick={()=>makeMainImage(url)} className="rounded-full bg-white px-3 py-1.5 text-[11px] font-bold">Үндсэн болгох</button>}<button type="button" disabled={index===0} onClick={()=>moveImage(index,-1)} className="rounded-full bg-white px-3 py-1.5 text-[11px] font-bold disabled:opacity-40">←</button><button type="button" disabled={index===productImages(editing).length-1} onClick={()=>moveImage(index,1)} className="rounded-full bg-white px-3 py-1.5 text-[11px] font-bold disabled:opacity-40">→</button><button type="button" onClick={()=>removeImage(url)} className="rounded-full bg-red-50 px-3 py-1.5 text-[11px] font-bold text-red-600">Устгах</button></div></div>)}</div>:<div className="mt-4 grid min-h-32 place-items-center rounded-2xl bg-cloud p-6 text-center text-sm font-bold text-neutral-400">Зураг сонгоно уу</div>}<details className="mt-3 rounded-xl bg-cloud px-4 py-3"><summary className="cursor-pointer text-xs font-bold">Зурагны холбоосоор нэмэх</summary><div className="mt-3 flex gap-2"><input className="input" placeholder="/images/tomoc-beauty-campaign.png эсвэл https://..." value={editing.imageUrl} onChange={event=>setUrlInput(event.target.value)} onPaste={event=>{const pasted=event.clipboardData.getData("text");if(pasted){event.preventDefault();setUrlInput(pasted.trim())}}}/><button type="button" onClick={addUrlImage} className="btn bg-white px-4">Нэмэх</button></div><span className="mt-1 block text-[11px] font-normal text-neutral-500">Энэ нь одоо байгаа зургуудыг солихгүй, жагсаалтын төгсгөлд нэмэгдэнэ.</span></details></div><label className="text-xs font-bold lg:col-span-2">Давуу талууд<input className="input mt-1" placeholder="таслалаар тусгаарлана" value={(editing.benefits||[]).join(", ")} onChange={event=>setEditing({...editing,benefits:event.target.value.split(",").map(item=>item.trim()).filter(Boolean)})}/></label><label className="text-xs font-bold lg:col-span-2">Тайлбар<textarea className="input mt-1 h-28 py-3" value={editing.description||""} onChange={event=>setEditing({...editing,description:event.target.value})}/></label></div><div className="mt-5 flex flex-wrap gap-3"><label className="flex items-center gap-2 rounded-xl bg-white px-4 py-3 text-sm font-bold"><input type="checkbox" checked={editing.is_active} onChange={event=>setEditing({...editing,is_active:event.target.checked})}/> Идэвхтэй</label><label className="flex items-center gap-2 rounded-xl bg-white px-4 py-3 text-sm font-bold"><input type="checkbox" checked={Boolean(editing.is_featured)} onChange={event=>setEditing({...editing,is_featured:event.target.checked})}/> Онцлох</label></div><div className="mt-5 flex gap-2"><button disabled={busy||!token} onClick={submit} className="btn btn-black disabled:opacity-40">{busy?<><LoaderCircle className="animate-spin" size={17}/> Хадгалж байна...</>:"Хадгалах"}</button><button disabled={busy} onClick={()=>setEditing(null)} className="btn bg-white disabled:opacity-40">Болих</button></div></div>}
  </section>
}

function ProductsTableV2({products,categories,token,onSaved}:{products:LiveProduct[],categories:Category[],token:string|null,onSaved:()=>void|Promise<void>}){
  type ProductForm=LiveProduct&{isNew?:boolean;imageUrl:string;variants:LiveVariant[]};
  const categoryName=(id?:string|null)=>categories.find(category=>category.id===id)?.name||"Ангилалгүй";
  const sizeVariants=(variants?:LiveVariant[])=>(variants||[]).filter(variant=>["size","размер","хэмжээ"].some(name=>variant.name.toLowerCase().includes(name))).map(variant=>({id:variant.id,name:"size",value:variant.value,stock:Math.max(0,Math.round(Number(variant.stock)||0)),price_delta:variant.price_delta||0}));
  const emptyForm=():ProductForm=>({id:"",name:"",slug:"",description:"",benefits:[],price:0,stock:0,is_active:true,is_featured:false,images:[],imageUrl:"",category_id:categories[0]?.id||null,variants:[],isNew:true});
  const toForm=(product:LiveProduct):ProductForm=>({...product,images:product.images||[],imageUrl:"",benefits:product.benefits||[],is_featured:Boolean(product.is_featured),variants:sizeVariants(product.product_variants)});
  const [query,setQuery]=useState("");
  const [editing,setEditing]=useState<ProductForm|null>(null);
  const [busy,setBusy]=useState(false);
  const [message,setMessage]=useState("");
  const [error,setError]=useState("");
  const [imagePreviewErrors,setImagePreviewErrors]=useState<Record<string,boolean>>({});
  const [uploadingImage,setUploadingImage]=useState(false);
  const [uploadProgress,setUploadProgress]=useState(0);
  const imageInputRef=useRef<HTMLInputElement|null>(null);
  const filtered=useMemo(()=>products.filter(product=>`${product.name} ${product.slug}`.toLowerCase().includes(query.toLowerCase())),[products,query]);
  const productImages=(form:ProductForm)=>Array.from(new Set((form.images||[]).map(url=>url.trim()).filter(Boolean))).slice(0,8);
  const cleanVariants=(form:ProductForm)=>form.variants.map(variant=>({name:"size",value:variant.value.trim(),stock:Math.max(0,Math.round(Number(variant.stock)||0)),price_delta:0})).filter(variant=>variant.value).slice(0,20);
  const startCreate=()=>{setError("");setMessage("");setImagePreviewErrors({});setEditing(emptyForm())};
  const startEdit=(product:LiveProduct)=>{setError("");setMessage("");setImagePreviewErrors({});setEditing(toForm(product))};
  const appendImages=(urls:string[])=>setEditing(current=>{if(!current)return current;const next=Array.from(new Set([...(current.images||[]),...urls.map(url=>url.trim()).filter(Boolean)])).slice(0,8);return {...current,images:next}});
  const removeImage=(url:string)=>{setImagePreviewErrors(current=>{const next={...current};delete next[url];return next});setEditing(current=>current?{...current,images:(current.images||[]).filter(item=>item!==url)}:current)};
  const makeMainImage=(url:string)=>setEditing(current=>current?{...current,images:[url,...(current.images||[]).filter(item=>item!==url)]}:current);
  const moveImage=(index:number,direction:-1|1)=>setEditing(current=>{if(!current)return current;const images=productImages(current);const nextIndex=index+direction;if(nextIndex<0||nextIndex>=images.length)return current;const next=[...images];[next[index],next[nextIndex]]=[next[nextIndex],next[index]];return {...current,images:next}});
  const setVariant=(index:number,field:"value"|"stock",value:string)=>setEditing(current=>current?{...current,variants:current.variants.map((variant,itemIndex)=>itemIndex===index?{...variant,[field]:field==="stock"?normalizeWholeNumber(value):value}:variant)}:current);
  const addVariant=()=>setEditing(current=>current?{...current,variants:[...current.variants,{name:"size",value:"",stock:0,price_delta:0}]}:current);
  const removeVariant=(index:number)=>setEditing(current=>current?{...current,variants:current.variants.filter((_,itemIndex)=>itemIndex!==index)}:current);
  const addUrlImage=()=>{if(!editing)return;const url=editing.imageUrl.trim();if(!url)return setError("Зураг сонгоно уу");if(productImages(editing).length>=8)return setError("8-аас олон зураг оруулах боломжгүй");appendImages([url]);setEditing(current=>current?{...current,imageUrl:""}:current);setError("")};
  const uploadImage=async(files:FileList|null)=>{const selected=Array.from(files||[]);if(imageInputRef.current)imageInputRef.current.value="";if(!token)return setError("Нэвтрэх шаардлагатай.");if(!selected.length)return setError("Зураг сонгоно уу");if((editing?.images?.length||0)+selected.length>8)return setError("8-аас олон зураг оруулах боломжгүй");if(selected.some(file=>!imageUploadTypes.has(file.type)))return setError("Зөвхөн JPG, PNG, WEBP зураг оруулна уу");if(selected.some(file=>file.size>5*1024*1024))return setError("Зураг 5MB-аас их байна");setUploadingImage(true);setUploadProgress(10);setError("");setMessage("");try{const form=new FormData();selected.forEach(file=>form.append("files",file));setUploadProgress(35);const response=await fetch("/api/admin/upload",{method:"POST",headers:{authorization:`Bearer ${token}`},body:form});setUploadProgress(75);const result=await response.json().catch(()=>({success:false,error:"Серверээс буруу хариу ирлээ."}));if(!response.ok||result.success===false||!Array.isArray(result.urls)||!result.urls.length)throw new Error(result.error||"Зураг upload хийхэд алдаа гарлаа");appendImages(result.urls);setUploadProgress(100);setMessage("Зураг upload хийгдлээ. Бүтээгдэхүүнээ хадгална уу.")}catch(cause){setError(`Зураг upload хийхэд алдаа гарлаа${cause instanceof Error&&cause.message?`: ${cause.message}`:""}`)}finally{window.setTimeout(()=>{setUploadingImage(false);setUploadProgress(0)},350)}};
  const submit=async()=>{if(!token||!editing)return;setBusy(true);setError("");setMessage("");const name=editing.name.trim();const slug=productSlug(editing.slug,name);const price=Math.max(0,Math.round(Number(editing.price)||0));const stock=Math.max(0,Math.round(Number(editing.stock)||0));const images=productImages(editing);const variants=cleanVariants(editing);try{if(!name)throw new Error("Нэр оруулна уу");if(price<=0)throw new Error("Үнэ зөв оруулна уу");if(!editing.category_id)throw new Error("Ангилал сонгоно уу");if(!images.length)throw new Error("Зураг сонгоно уу");const response=await fetch("/api/admin",{method:editing.isNew?"POST":"PATCH",headers:{"content-type":"application/json",authorization:`Bearer ${token}`},body:JSON.stringify({resource:"products",id:editing.id,name,slug,price,stock,category_id:editing.category_id,benefits:editing.benefits||[],description:editing.description||"",images,is_active:Boolean(editing.is_active),is_featured:Boolean(editing.is_featured),variants})});const result=await response.json().catch(()=>({success:false,error:"Серверээс буруу хариу ирлээ."}));if(!response.ok||result.success===false)throw new Error(result.error||"Бүтээгдэхүүн хадгалахад алдаа гарлаа.");setEditing(null);await Promise.resolve(onSaved());setMessage(editing.isNew?"Бүтээгдэхүүн амжилттай нэмэгдлээ.":"Бүтээгдэхүүн амжилттай шинэчлэгдлээ.")}catch(cause){setError(cause instanceof Error?cause.message:"Бүтээгдэхүүн хадгалахад алдаа гарлаа.")}finally{setBusy(false)}};
  const toggleActive=async(product:LiveProduct)=>{if(!token)return;setBusy(true);setError("");setMessage("");try{const response=await fetch("/api/admin",{method:"PATCH",headers:{"content-type":"application/json",authorization:`Bearer ${token}`},body:JSON.stringify({resource:"product_status",id:product.id,is_active:!product.is_active})});const result=await response.json().catch(()=>({success:false,error:"Серверээс буруу хариу ирлээ."}));if(!response.ok||result.success===false)throw new Error(result.error||"Бүтээгдэхүүний төлөв шинэчилж чадсангүй.");await Promise.resolve(onSaved());setMessage("Бүтээгдэхүүний төлөв шинэчлэгдлээ.")}catch(cause){setError(cause instanceof Error?cause.message:"Алдаа гарлаа.")}finally{setBusy(false)}};
  return <section className="overflow-hidden rounded-3xl bg-white">
    <div className="flex flex-col justify-between gap-4 p-5 md:flex-row md:items-center md:p-6"><div><h2 className="font-bold">Бүтээгдэхүүний удирдлага</h2><p className="text-xs text-neutral-400">Бараа, зураг, үнэ, размерын үлдэгдлээ энгийнээр удирдана.</p></div><div className="flex flex-col gap-2 sm:flex-row"><div className="relative"><Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-400"/><input className="h-10 w-full rounded-xl bg-cloud pl-9 pr-4 text-sm outline-none" placeholder="Нэр эсвэл slug хайх" value={query} onChange={event=>setQuery(event.target.value)}/></div><button disabled={!token||busy} onClick={startCreate} className="btn btn-black h-10 text-sm disabled:opacity-40"><Plus size={16}/> Шинэ бүтээгдэхүүн</button></div></div>
    {error&&<div role="alert" className="mx-5 mb-4 rounded-xl bg-red-50 p-3 text-sm text-red-700">{error}</div>}{message&&<div role="status" className="mx-5 mb-4 rounded-xl bg-green-50 p-3 text-sm font-bold text-green-700">{message}</div>}
    <div className="overflow-auto"><table className="w-full min-w-[1040px] text-left text-sm"><thead className="bg-cloud text-xs text-neutral-500"><tr><th className="px-6 py-3">Зураг</th><th>Нэр</th><th>Slug</th><th>Үнэ</th><th>Үлдэгдэл</th><th>Размер</th><th>Ангилал</th><th>Төлөв</th><th>Онцлох</th><th></th></tr></thead><tbody>{filtered.length?filtered.map(product=><tr key={product.id} className="border-t border-black/5"><td className="px-6 py-3"><div className="h-14 w-14 overflow-hidden rounded-xl bg-cloud"><img src={product.images?.[0]||"/images/tomoc-beauty-campaign.png"} className="h-full w-full object-cover" alt=""/></div></td><td className="font-bold">{product.name}</td><td className="max-w-[160px] truncate text-xs text-neutral-500">/{product.slug}</td><td className="font-bold">{money(product.price)}</td><td>{product.stock}</td><td className="max-w-[180px] text-xs text-neutral-500">{sizeVariants(product.product_variants).map(variant=>`${variant.value}: ${variant.stock}`).join(", ")||"—"}</td><td>{categoryName(product.category_id)}</td><td><span className={`rounded-full px-3 py-1 text-xs font-bold ${product.is_active?"bg-green-100 text-green-700":"bg-neutral-100 text-neutral-500"}`}>{product.is_active?"Идэвхтэй":"Нуусан"}</span></td><td>{product.is_featured?"Тийм":"Үгүй"}</td><td><div className="flex gap-3"><button disabled={!token||busy} onClick={()=>startEdit(product)} className="font-bold disabled:text-neutral-300">Засах</button><button disabled={!token||busy} onClick={()=>toggleActive(product)} className={product.is_active?"text-red-600 disabled:text-neutral-300":"text-green-700 disabled:text-neutral-300"}>{product.is_active?"Нуух":"Ил гаргах"}</button></div></td></tr>):<tr><td colSpan={10} className="px-6 py-14 text-center text-neutral-400">Хайлтад тохирох бүтээгдэхүүн алга.</td></tr>}</tbody></table></div>
    {editing&&<div className="border-t border-black/10 bg-cloud p-5 md:p-7"><div className="flex items-center justify-between"><div><p className="eyebrow">{editing.isNew?"CREATE PRODUCT":"EDIT PRODUCT"}</p><h3 className="mt-1 text-xl font-bold">{editing.isNew?"Шинэ бүтээгдэхүүн":"Бүтээгдэхүүн засах"}</h3></div><button disabled={busy} onClick={()=>setEditing(null)} className="grid h-10 w-10 place-items-center rounded-full bg-white disabled:opacity-40" aria-label="Хаах"><X size={18}/></button></div><div className="mt-5 grid gap-4 lg:grid-cols-2"><label className="text-xs font-bold">Нэр<input className="input mt-1" value={editing.name} onChange={event=>setEditing({...editing,name:event.target.value})}/></label><label className="text-xs font-bold">Линк нэр / Slug<input className="input mt-1" value={editing.slug} placeholder="Хоосон бол автоматаар үүснэ" onChange={event=>setEditing({...editing,slug:event.target.value})}/></label><label className="text-xs font-bold">Үнэ<input inputMode="numeric" className="input mt-1" value={editing.price||""} placeholder="85000" onChange={event=>setEditing({...editing,price:normalizeWholeNumber(event.target.value)})}/></label><label className="text-xs font-bold">Нийт үлдэгдэл<input inputMode="numeric" className="input mt-1" value={editing.stock||""} placeholder="20" onChange={event=>setEditing({...editing,stock:normalizeWholeNumber(event.target.value)})}/></label><label className="text-xs font-bold">Ангилал<select className="input mt-1" value={editing.category_id||""} onChange={event=>setEditing({...editing,category_id:event.target.value||null})}><option value="">Ангилал сонгох</option>{categories.map(category=><option key={category.id} value={category.id}>{category.name}</option>)}</select></label>
      <div className="rounded-2xl bg-white p-4 lg:col-span-2"><div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between"><div><h4 className="text-sm font-black">Бүтээгдэхүүний зураг</h4><p className="mt-1 text-xs text-neutral-500">8 хүртэл зураг upload хийнэ. Эхний зураг үндсэн зураг болно.</p><p className="mt-1 text-[11px] font-bold text-neutral-400">{productImages(editing).length}/8 зураг</p></div><div className="flex flex-wrap gap-2"><input ref={imageInputRef} type="file" multiple accept="image/jpeg,image/png,image/webp" className="hidden" onChange={event=>uploadImage(event.target.files)}/><button type="button" disabled={uploadingImage||busy||productImages(editing).length>=8} onClick={()=>imageInputRef.current?.click()} className="btn btn-black h-10 text-xs disabled:opacity-40">{uploadingImage?<><LoaderCircle className="animate-spin" size={15}/> Upload хийж байна...</>:"Зураг upload хийх"}</button></div></div>{uploadingImage&&<div className="mt-4 rounded-full bg-cloud p-1"><div className="h-2 rounded-full bg-ink transition-all" style={{width:`${uploadProgress}%`}}/><p className="mt-2 text-xs font-bold text-neutral-500">Зураг upload хийж байна... {uploadProgress}%</p></div>}{productImages(editing).length?<div className="mt-4 grid gap-3 sm:grid-cols-2 lg:grid-cols-4">{productImages(editing).map((url,index)=><div key={`${url}-${index}`} className="rounded-2xl bg-cloud p-2"><div className="relative h-32 overflow-hidden rounded-xl bg-white">{!imagePreviewErrors[url]?<img src={url} alt={`Бүтээгдэхүүний зураг ${index+1}`} className="h-full w-full object-cover" onLoad={()=>setImagePreviewErrors(current=>({...current,[url]:false}))} onError={()=>setImagePreviewErrors(current=>({...current,[url]:true}))}/>:<div className="grid h-full w-full place-items-center px-3 text-center text-[11px] font-bold text-red-600">Зураг харагдахгүй байна</div>}{index===0&&<span className="absolute left-2 top-2 rounded-full bg-ink px-2 py-1 text-[10px] font-bold text-white">Үндсэн зураг</span>}</div><p className="mt-2 truncate text-[11px] text-neutral-500">{url}</p><div className="mt-2 flex flex-wrap gap-2">{index>0&&<button type="button" onClick={()=>makeMainImage(url)} className="rounded-full bg-white px-3 py-1.5 text-[11px] font-bold">Үндсэн болгох</button>}<button type="button" disabled={index===0} onClick={()=>moveImage(index,-1)} className="rounded-full bg-white px-3 py-1.5 text-[11px] font-bold disabled:opacity-40">←</button><button type="button" disabled={index===productImages(editing).length-1} onClick={()=>moveImage(index,1)} className="rounded-full bg-white px-3 py-1.5 text-[11px] font-bold disabled:opacity-40">→</button><button type="button" onClick={()=>removeImage(url)} className="rounded-full bg-red-50 px-3 py-1.5 text-[11px] font-bold text-red-600">Устгах</button></div></div>)}</div>:<div className="mt-4 grid min-h-32 place-items-center rounded-2xl bg-cloud p-6 text-center text-sm font-bold text-neutral-400">Зураг сонгоно уу</div>}<details className="mt-3 rounded-xl bg-cloud px-4 py-3"><summary className="cursor-pointer text-xs font-bold">Зурагны холбоосоор нэмэх</summary><div className="mt-3 flex gap-2"><input className="input" placeholder="/images/tomoc-beauty-campaign.png эсвэл https://..." value={editing.imageUrl} onChange={event=>setEditing({...editing,imageUrl:event.target.value})}/><button type="button" onClick={addUrlImage} className="btn bg-white px-4">Нэмэх</button></div></details></div>
      <div className="rounded-2xl bg-white p-4 lg:col-span-2"><div className="flex items-center justify-between gap-3"><div><h4 className="text-sm font-black">Размерын үлдэгдэл</h4><p className="mt-1 text-xs text-neutral-500">Жишээ: XS, S, M, L, XL. Chatbot энэ мэдээллийг шууд уншина.</p></div><button type="button" onClick={addVariant} className="btn bg-cloud h-10 text-xs"><Plus size={14}/> Размер нэмэх</button></div><div className="mt-4 space-y-2">{editing.variants.length?editing.variants.map((variant,index)=><div key={`${variant.value}-${index}`} className="grid gap-2 rounded-2xl bg-cloud p-3 sm:grid-cols-[1fr_140px_auto]"><input className="input bg-white" placeholder="Размер: XS" value={variant.value} onChange={event=>setVariant(index,"value",event.target.value.toUpperCase())}/><input inputMode="numeric" className="input bg-white" placeholder="Үлдэгдэл" value={variant.stock||""} onChange={event=>setVariant(index,"stock",event.target.value)}/><button type="button" onClick={()=>removeVariant(index)} className="rounded-xl bg-red-50 px-4 text-xs font-bold text-red-600">Устгах</button></div>):<p className="rounded-2xl bg-cloud p-4 text-sm text-neutral-500">Размер байхгүй бол хоосон үлдээж болно.</p>}</div></div>
      <label className="text-xs font-bold lg:col-span-2">Давуу талууд<input className="input mt-1" placeholder="таслалаар тусгаарлана" value={(editing.benefits||[]).join(", ")} onChange={event=>setEditing({...editing,benefits:event.target.value.split(",").map(item=>item.trim()).filter(Boolean)})}/></label><label className="text-xs font-bold lg:col-span-2">Тайлбар<textarea className="input mt-1 h-28 py-3" value={editing.description||""} onChange={event=>setEditing({...editing,description:event.target.value})}/></label></div><div className="mt-5 flex flex-wrap gap-3"><label className="flex items-center gap-2 rounded-xl bg-white px-4 py-3 text-sm font-bold"><input type="checkbox" checked={editing.is_active} onChange={event=>setEditing({...editing,is_active:event.target.checked})}/> Идэвхтэй</label><label className="flex items-center gap-2 rounded-xl bg-white px-4 py-3 text-sm font-bold"><input type="checkbox" checked={Boolean(editing.is_featured)} onChange={event=>setEditing({...editing,is_featured:event.target.checked})}/> Онцлох</label></div><div className="mt-5 flex gap-2"><button disabled={busy||!token} onClick={submit} className="btn btn-black disabled:opacity-40">{busy?<><LoaderCircle className="animate-spin" size={17}/> Хадгалж байна...</>:"Хадгалах"}</button><button disabled={busy} onClick={()=>setEditing(null)} className="btn bg-white disabled:opacity-40">Болих</button></div></div>}
  </section>
}

